var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흑...... 흐윽......","JPN":"う……ううっ……","ENG":"Hngh... Hnngh...","TWN":"嗚……嗚嗚……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그만 좀 울어! 애도 아니고 왜 그래?","JPN":"もういい加減、子どもみたいにめそめそしないで！","ENG":"Stop crying! Don't be such a baby! What's wrong with you?","TWN":"別哭了！又不是小孩子？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그치만...... 난 대체 뭘 위해 노력해 온 거지?","JPN":"で、でも……私はいったい何のために努力してきたの……？","ENG":"B-but... What have I been working so hard for?","TWN":"但、但是......我到底是為了什麼努力的呢？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"내 힘 같은 건...... 전혀 통하지 않았어......","JPN":"私の力なんか……全然通じなかった……","ENG":"My powers are nothing... They are useless...","TWN":"我的力量……完全不夠看……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"겨우 이 따위 실력으로 인류의 영웅이니 뭐니 하는 소릴 하다니......","JPN":"こんな実力で人類の英雄になるとかほざいて……","ENG":"I can't believe I babbled on about becoming a hero with such pathetic skills...","TWN":"以這樣的實力還誇口說要成為人類的英雄……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"난...... 난 진짜 쓰레기야......","JPN":"私は……私はゴミ同然だよ……","ENG":"I'm... I'm just garbage...","TWN":"我……我真的是垃圾……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"폐품, 고물, 플라스틱 포장지만도 못한 존재라고......!","JPN":"がらくた、クズ、リサイクルすらできないポリ袋以下の存在なんだよ……！","ENG":"I'm more worthless than meat bones, soda cans, and plastic wrappers! ","TWN":"廢物、沒用的東西，連塑膠袋都不如的存在……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"으으, 진짜. 자다 깬 이디스 선배도 너처럼 히스테리 부리진 않겠다.","JPN":"もー、呆れるね。寝起きのイーディス先輩でもそんなヒステリックにならないよ。","ENG":"Ugh, stop it. Even Edith who just wakes up won't be hysterical like you.","TWN":"喂喂，夠了。就算是剛睡醒的伊蒂絲前輩也不會像你這樣歇斯底里。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"레이 선배, 그만 업어 줘요. 우는 거 보니까 혼자서도 잘 걷겠네.","JPN":"レイ先輩、もう歩かせましょう。こんなに大きな声で元気に泣いてるし、もう歩けるでしょう。","ENG":"I think you can put her down now, Ray. She can probably walk just fine if she's got the energy to cry.","TWN":"雷伊前輩，你不用背她了。看她哭的樣子，應該能自己走路。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"괘, 괜찮아. 부상이 나으려면 안정을 취해야 하잖아.","JPN":"だ、大丈夫。傷を早く治すためにも、もう少し安静にしないとだから。","ENG":"I-it's okay. She needs plenty of rest to heal up.","TWN":"沒、沒關係。要想讓傷口快點痊癒，需要休息。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"그리고...... 난 나이엘이 쓰레기라고 생각하지 않아.","JPN":"それに……僕もナイエルのこと、ゴミと思ってないから。","ENG":"Besides... I don't think you're garbage, Naielle.","TWN":"還有……我不認為奈爾是垃圾。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐......?","JPN":"え……？","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"선배, 말했잖아요. 사람 좋은 것도 정도가 있다니까요.","JPN":"先輩、この前も言ったけどお人好しにもほどがあるんですよ。","ENG":"Haven't I told you, Ray? Sometimes you're way too nice for your own good.","TWN":"前輩，我都說了，做好人也該有個限度。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"걔가 그동안 선배한테 얼마나 심한 말을 하고 다녔는지 기억 안 나요?","JPN":"その子に今までどれだけ酷いことを言われてきたか、覚えていないんですか？","ENG":"Did you already forget how awful she's been to you?","TWN":"難道你忘了她以前對前輩說了多少難聽的話嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"그게...... 나도 나이엘의 방식이 좋지 않다고 봐. 너무 과격하니까.","JPN":"それは……僕もナイエルのやり方はよくないと思ってはいるよ。過激すぎるからね。","ENG":"Well... I don't agree with Naielle's methods either. It's far too aggressive.","TWN":"那個……我也認為奈爾說話跟做事的方式不太好，有些過於激烈了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 나이엘도 사람들을 지키기 위해서 강해지려고 했던 거잖아.","JPN":"でもナイエルだって、人を守るために強くなろうとしたんでしょ。","ENG":"But all Naielle wanted was to get stronger so she can protect people.","TWN":"但奈爾想變得更強也是為了保護人類。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"이번 일로 충격이 크겠지만, 그만큼 많이 배웠을 거라고 생각해.","JPN":"今回のことでショックは大きいだろうけど、その分勉強になったと思うよ。","ENG":"I'm sure this must have been traumatic, but a learning experience too.","TWN":"雖然這裡的事情會讓她很受打擊，但她也會學到很多東西。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};